import { useTaskStore } from '@/stores/taskStore'

describe('TaskFilters', () => {
  let store: ReturnType<typeof useTaskStore>

  beforeEach(() => {
    setActivePinia(createPinia())
    store = useTaskStore()
    vi.clearAllMocks()
  })

  describe('keyword filter', () => {
    it('should update keyword in store and reset page to 0', () => {
      store.page = 3
      store.setKeyword('search term')

      expect(store.keyword).toBe('search term')
      expect(store.page).toBe(0)
    })

    it('should handle empty keyword', () => {
      store.setKeyword('something')
      store.setKeyword('')

      expect(store.keyword).toBe('')
      expect(store.page).toBe(0)
    })
  })

  describe('priority filter', () => {
    it('should set priority to HIGH and reset page', () => {
      store.page = 2
      store.setPriorityFilter('HIGH')

      expect(store.priorityFilter).toBe('HIGH')
      expect(store.page).toBe(0)
    })

    it('should set priority to MEDIUM', () => {
      store.setPriorityFilter('MEDIUM')
      expect(store.priorityFilter).toBe('MEDIUM')
    })

    it('should set priority to LOW', () => {
      store.setPriorityFilter('LOW')
      expect(store.priorityFilter).toBe('LOW')
    })

    it('should clear priority filter with empty string (select all)', () => {
      store.setPriorityFilter('HIGH')
      store.setPriorityFilter('')

      expect(store.priorityFilter).toBe('')
    })
  })

  describe('status filter', () => {
    it('should set status to TODO and reset page', () => {
      store.page = 5
      store.setStatusFilter('TODO')

      expect(store.statusFilter).toBe('TODO')
      expect(store.page).toBe(0)
    })

    it('should set status to IN_PROGRESS', () => {
      store.setStatusFilter('IN_PROGRESS')
      expect(store.statusFilter).toBe('IN_PROGRESS')
    })

    it('should set status to DONE', () => {
      store.setStatusFilter('DONE')
      expect(store.statusFilter).toBe('DONE')
    })

    it('should set status to CLOSED', () => {
      store.setStatusFilter('CLOSED')
      expect(store.statusFilter).toBe('CLOSED')
    })

    it('should clear status filter with empty string (select all)', () => {
      store.setStatusFilter('TODO')
      store.setStatusFilter('')

      expect(store.statusFilter).toBe('')
    })
  })

  describe('combined filters', () => {
    it('should allow setting keyword, priority, and status together', () => {
      store.setKeyword('bug fix')
      store.setPriorityFilter('HIGH')
      store.setStatusFilter('IN_PROGRESS')

      expect(store.keyword).toBe('bug fix')
      expect(store.priorityFilter).toBe('HIGH')
      expect(store.statusFilter).toBe('IN_PROGRESS')
      expect(store.page).toBe(0)
    })

    it('should maintain other filters when one changes', () => {
      store.setKeyword('test')
      store.setPriorityFilter('LOW')
      store.setStatusFilter('DONE')

      // Change only keyword
      store.setKeyword('new keyword')

      expect(store.keyword).toBe('new keyword')
      expect(store.priorityFilter).toBe('LOW')
      expect(store.statusFilter).toBe('DONE')
    })
  })

  describe('expected UI contract', () => {
    it('component should expose priority options: empty, HIGH, MEDIUM, LOW', () => {
      const expectedPriorities = ['', 'HIGH', 'MEDIUM', 'LOW']
      // The component should present these options in a dropdown
      // '' maps to "全部" label in UI
      expectedPriorities.forEach((p) => {
        store.setPriorityFilter(p)
        expect(store.priorityFilter).toBe(p)
      })
    })

    it('component should expose status options: empty, TODO, IN_PROGRESS, DONE, CLOSED', () => {
      const expectedStatuses = ['', 'TODO', 'IN_PROGRESS', 'DONE', 'CLOSED']
      // '' maps to "全部" label in UI
      expectedStatuses.forEach((s) => {
        store.setStatusFilter(s)
        expect(store.statusFilter).toBe(s)
      })
    })
  })
})

