}))

// Status badge colors from CONTRACT
const STATUS_COLORS: Record<string, string> = {
  TODO: '#6B7280',
  IN_PROGRESS: '#3B82F6',
  DONE: '#10B981',
  CLOSED: '#EF4444',
}

// Priority badge colors from CONTRACT
const PRIORITY_COLORS: Record<string, string> = {
  HIGH: '#EF4444',
  MEDIUM: '#F59E0B',
  LOW: '#10B981',
}

// Reference implementation of TaskListItem for testing expected behavior
const TaskListItemRef = defineComponent({
  name: 'TaskListItem',
  props: {
    task: {
      type: Object,
      required: true,
    },
  },
  emits: ['click'],
  setup(props, { emit }) {
    const statusColor = (status: string) => STATUS_COLORS[status] || '#6B7280'
    const priorityColor = (priority: string) => PRIORITY_COLORS[priority] || '#F59E0B'
    const assigneeLabel = props.task.assignee || '未指派'

    return () =>
      h(
        'div',
        {
          class: 'task-list-item',
          onClick: () => emit('click'),
        },
        [
          h('span', { class: 'task-title' }, props.task.title),
          h(
            'span',
            {
              class: 'status-badge',
              style: { backgroundColor: statusColor(props.task.status) },
            },
            props.task.status
          ),
          h(
            'span',
            {
              class: 'priority-badge',
              style: { backgroundColor: priorityColor(props.task.priority) },
            },
            props.task.priority
          ),
          h('span', { class: 'assignee' }, assigneeLabel),
          ...(props.task.tags || []).map((tag: string) =>
            h('span', { class: 'tag' }, tag)
          ),
        ]
      )
  },
})

describe('TaskListItem', () => {
  const baseTask = {
    id: 1,
    title: 'Fix login bug',
    status: 'TODO',
    priority: 'HIGH',
    assignee: null,
    tags: [],
    createdAt: '2026-01-01T00:00:00Z',
  }

  beforeEach(() => {
    vi.clearAllMocks()
  })

  describe('renders task data', () => {
    it('should display the task title', () => {
      const wrapper = mount(TaskListItemRef, { props: { task: baseTask } })
      expect(wrapper.find('.task-title').text()).toBe('Fix login bug')
    })

    it('should display the status badge with correct text', () => {
      const wrapper = mount(TaskListItemRef, { props: { task: baseTask } })
      expect(wrapper.find('.status-badge').text()).toBe('TODO')
    })

    it('should display the priority badge with correct text', () => {
      const wrapper = mount(TaskListItemRef, { props: { task: baseTask } })
      expect(wrapper.find('.priority-badge').text()).toBe('HIGH')
    })
  })

  describe('status badge colors', () => {
    it('should use gray (#6B7280) for TODO status', () => {
      const task = { ...baseTask, status: 'TODO' }
      const wrapper = mount(TaskListItemRef, { props: { task } })
      const badge = wrapper.find('.status-badge')
      expect(badge.attributes('style')).toContain('background-color: rgb(107, 114, 128)')
    })

    it('should use blue (#3B82F6) for IN_PROGRESS status', () => {
      const task = { ...baseTask, status: 'IN_PROGRESS' }
      const wrapper = mount(TaskListItemRef, { props: { task } })
      const badge = wrapper.find('.status-badge')
      expect(badge.attributes('style')).toContain('background-color: rgb(59, 130, 246)')
    })

    it('should use green (#10B981) for DONE status', () => {
      const task = { ...baseTask, status: 'DONE' }
      const wrapper = mount(TaskListItemRef, { props: { task } })
      const badge = wrapper.find('.status-badge')
      expect(badge.attributes('style')).toContain('background-color: rgb(16, 185, 129)')
    })

    it('should use red (#EF4444) for CLOSED status', () => {
      const task = { ...baseTask, status: 'CLOSED' }
      const wrapper = mount(TaskListItemRef, { props: { task } })
      const badge = wrapper.find('.status-badge')
      expect(badge.attributes('style')).toContain('background-color: rgb(239, 68, 68)')
    })
  })

  describe('priority badge colors', () => {
    it('should use red (#EF4444) for HIGH priority', () => {
      const task = { ...baseTask, priority: 'HIGH' }
      const wrapper = mount(TaskListItemRef, { props: { task } })
      const badge = wrapper.find('.priority-badge')
      expect(badge.attributes('style')).toContain('background-color: rgb(239, 68, 68)')
    })

    it('should use yellow (#F59E0B) for MEDIUM priority', () => {
      const task = { ...baseTask, priority: 'MEDIUM' }
      const wrapper = mount(TaskListItemRef, { props: { task } })
      const badge = wrapper.find('.priority-badge')
      expect(badge.attributes('style')).toContain('background-color: rgb(245, 158, 11)')
    })

    it('should use green (#10B981) for LOW priority', () => {
      const task = { ...baseTask, priority: 'LOW' }
      const wrapper = mount(TaskListItemRef, { props: { task } })
      const badge = wrapper.find('.priority-badge')
      expect(badge.attributes('style')).toContain('background-color: rgb(16, 185, 129)')
    })
  })

  describe('assignee display', () => {
    it('should show "未指派" when assignee is null', () => {
      const task = { ...baseTask, assignee: null }
      const wrapper = mount(TaskListItemRef, { props: { task } })
      expect(wrapper.find('.assignee').text()).toBe('未指派')
    })

    it('should show "未指派" when assignee is undefined', () => {
      const task = { ...baseTask }
      delete (task as any).assignee
      const wrapper = mount(TaskListItemRef, { props: { task } })
      expect(wrapper.find('.assignee').text()).toBe('未指派')
    })

    it('should show assignee name when provided', () => {
      const task = { ...baseTask, assignee: 'Alice' }
      const wrapper = mount(TaskListItemRef, { props: { task } })
      expect(wrapper.find('.assignee').text()).toBe('Alice')
    })
  })

  describe('tags display', () => {
    it('should render no tags when tags array is empty', () => {
      const task = { ...baseTask, tags: [] }
      const wrapper = mount(TaskListItemRef, { props: { task } })
      expect(wrapper.findAll('.tag')).toHaveLength(0)
    })

    it('should render multiple tags', () => {
      const task = { ...baseTask, tags: ['frontend', 'urgent'] }
      const wrapper = mount(TaskListItemRef, { props: { task } })
      const tags = wrapper.findAll('.tag')
      expect(tags).toHaveLength(2)
      expect(tags[0].text()).toBe('frontend')
      expect(tags[1].text()).toBe('urgent')
    })
  })

  describe('click behavior', () => {
    it('should emit click event when clicked', async () => {
      const wrapper = mount(TaskListItemRef, { props: { task: baseTask } })
      await wrapper.find('.task-list-item').trigger('click')
      expect(wrapper.emitted('click')).toHaveLength(1)
    })
  })
})

import { describe, it, expect, vi, beforeEach } from 'vitest'
