import { setActivePinia, createPinia } from 'pinia'

// Mock the tasks API
vi.mock('@/api/tasks', () => ({
  getTasks: vi.fn(),
  createTask: vi.fn(),
}))

// Mock axios
vi.mock('@/api/axios', () => ({
  default: {
    get: vi.fn(),
    post: vi.fn(),
    put: vi.fn(),
    delete: vi.fn(),
    patch: vi.fn(),
    defaults: { baseURL: '/api' },
