}))

import { useTaskStore } from '@/stores/taskStore'
import * as tasksApi from '@/api/tasks'

// Reference implementation for testing contracts
const TaskCreateFormRef = defineComponent({
  name: 'TaskCreateForm',
  props: {
    visible: {
      type: Boolean,
      default: false,
    },
  },
  emits: ['created', 'cancel'],
  setup(props, { emit }) {
    const form = reactive({
      title: '',
      description: '',
      priority: 'MEDIUM',
    })
    const titleError = ref('')

    const validate = () => {
      if (!form.title.trim()) {
        titleError.value = '標題為必填'
        return false
      }
      titleError.value = ''
      return true
    }

    const submit = async () => {
      if (!validate()) return
      const store = useTaskStore()
      await store.createTask({
        title: form.title,
        description: form.description,
        priority: form.priority,
      })
      form.title = ''
      form.description = ''
      form.priority = 'MEDIUM'
      emit('created')
    }

    const cancel = () => {
      form.title = ''
      form.description = ''
      form.priority = 'MEDIUM'
      titleError.value = ''
      emit('cancel')
    }

    return () => {
      if (!props.visible) return h('div', { class: 'task-create-form hidden' })

      return h('div', { class: 'task-create-form' }, [
        h('form', { onSubmit: (e: Event) => { e.preventDefault(); submit() } }, [
          h('div', { class: 'form-group' }, [
            h('label', { for: 'title' }, '標題'),
            h('input', {
              id: 'title',
              class: 'title-input',
              value: form.title,
              onInput: (e: Event) => { form.title = (e.target as HTMLInputElement).value },
              required: true,
            }),
            titleError.value
              ? h('span', { class: 'error-message' }, titleError.value)
              : null,
          ]),
          h('div', { class: 'form-group' }, [
            h('label', { for: 'description' }, '描述'),
            h('textarea', {
              id: 'description',
              class: 'description-input',
              value: form.description,
              onInput: (e: Event) => { form.description = (e.target as HTMLTextAreaElement).value },
            }),
          ]),
          h('div', { class: 'form-group' }, [
            h('label', { for: 'priority' }, '優先級'),
            h('select', {
              id: 'priority',
              class: 'priority-select',
              value: form.priority,
              onChange: (e: Event) => { form.priority = (e.target as HTMLSelectElement).value },
            }, [
              h('option', { value: 'HIGH' }, 'HIGH'),
              h('option', { value: 'MEDIUM' }, 'MEDIUM'),
              h('option', { value: 'LOW' }, 'LOW'),
            ]),
          ]),
          h('button', { type: 'submit', class: 'submit-btn' }, '建立'),
          h('button', { type: 'button', class: 'cancel-btn', onClick: cancel }, '取消'),
        ]),
      ])
    }
  },
})

describe('TaskCreateForm', () => {
  beforeEach(() => {
    setActivePinia(createPinia())
    vi.clearAllMocks()
  })

  describe('visibility', () => {
    it('should be hidden when visible prop is false', () => {
      const wrapper = mount(TaskCreateFormRef, { props: { visible: false } })
      expect(wrapper.find('.task-create-form').classes()).toContain('hidden')
      expect(wrapper.find('form').exists()).toBe(false)
    })

    it('should show form when visible prop is true', () => {
      const wrapper = mount(TaskCreateFormRef, { props: { visible: true } })
      expect(wrapper.find('.task-create-form').classes()).not.toContain('hidden')
      expect(wrapper.find('form').exists()).toBe(true)
    })
  })

  describe('form defaults', () => {
    it('should have empty title by default', () => {
      const wrapper = mount(TaskCreateFormRef, { props: { visible: true } })
      const input = wrapper.find('.title-input')
      expect((input.element as HTMLInputElement).value).toBe('')
    })

    it('should have empty description by default', () => {
      const wrapper = mount(TaskCreateFormRef, { props: { visible: true } })
      const textarea = wrapper.find('.description-input')
      expect((textarea.element as HTMLTextAreaElement).value).toBe('')
    })

    it('should default priority to MEDIUM', () => {
      const wrapper = mount(TaskCreateFormRef, { props: { visible: true } })
      const select = wrapper.find('.priority-select')
      expect((select.element as HTMLSelectElement).value).toBe('MEDIUM')
    })
  })

  describe('form validation', () => {
    it('should show error when title is empty on submit', async () => {
      const wrapper = mount(TaskCreateFormRef, { props: { visible: true } })

      await wrapper.find('form').trigger('submit')

      expect(wrapper.find('.error-message').text()).toBe('標題為必填')
    })

    it('should show error when title is whitespace only', async () => {
      const wrapper = mount(TaskCreateFormRef, { props: { visible: true } })
      await wrapper.find('.title-input').setValue('   ')

      await wrapper.find('form').trigger('submit')

      expect(wrapper.find('.error-message').text()).toBe('標題為必填')
    })

    it('should not show error when title is provided', async () => {
