    it('should emit created event after successful creation', async () => {
      vi.mocked(tasksApi.createTask).mockResolvedValue({ id: 1, title: 'Test', status: 'TODO' })
      vi.mocked(tasksApi.getTasks).mockResolvedValue({
        content: [],
        page: 0,
        size: 20,
        totalElements: 0,
        totalPages: 0,
      })

      const wrapper = mount(TaskCreateFormRef, { props: { visible: true } })
      await wrapper.find('.title-input').setValue('Test')

      await wrapper.find('form').trigger('submit')
      await flushPromises()

      expect(wrapper.emitted('created')).toHaveLength(1)
    })

    it('should reset form after successful creation', async () => {
      vi.mocked(tasksApi.createTask).mockResolvedValue({ id: 1, title: 'Test', status: 'TODO' })
      vi.mocked(tasksApi.getTasks).mockResolvedValue({
        content: [],
        page: 0,
        size: 20,
        totalElements: 0,
        totalPages: 0,
      })

      const wrapper = mount(TaskCreateFormRef, { props: { visible: true } })
      await wrapper.find('.title-input').setValue('Test')
      await wrapper.find('.description-input').setValue('Desc')

      await wrapper.find('form').trigger('submit')
      await flushPromises()

      expect((wrapper.find('.title-input').element as HTMLInputElement).value).toBe('')
      expect((wrapper.find('.description-input').element as HTMLTextAreaElement).value).toBe('')
      expect((wrapper.find('.priority-select').element as HTMLSelectElement).value).toBe('MEDIUM')
    })

    it('should not call createTask when title is empty', async () => {
      const wrapper = mount(TaskCreateFormRef, { props: { visible: true } })

      await wrapper.find('form').trigger('submit')

      expect(tasksApi.createTask).not.toHaveBeenCalled()
    })
  })

  describe('cancel', () => {
    it('should emit cancel event when cancel button clicked', async () => {
      const wrapper = mount(TaskCreateFormRef, { props: { visible: true } })

      await wrapper.find('.cancel-btn').trigger('click')

      expect(wrapper.emitted('cancel')).toHaveLength(1)
