import { describe, it, expect, vi, beforeEach } from 'vitest'
import { mount } from '@vue/test-utils'
import { defineComponent, h } from 'vue'

// Reference implementation for testing expected behavior
const PaginationRef = defineComponent({
  name: 'Pagination',
  props: {
    currentPage: {
      type: Number,
      required: true,
    },
    totalPages: {
      type: Number,
      required: true,
    },
  },
  emits: ['page-change'],
  setup(props, { emit }) {
    const goPrev = () => {
      if (props.currentPage > 0) {
        emit('page-change', props.currentPage - 1)
      }
    }

    const goNext = () => {
      if (props.currentPage < props.totalPages - 1) {
        emit('page-change', props.currentPage + 1)
      }
    }

    return () =>
      h('div', { class: 'pagination' }, [
        h(
          'button',
          {
            class: 'prev-btn',
            disabled: props.currentPage <= 0,
            onClick: goPrev,
          },
          '上一頁'
        ),
        h('span', { class: 'page-info' }, `${props.currentPage + 1} / ${props.totalPages}`),
        h(
          'button',
          {
            class: 'next-btn',
            disabled: props.currentPage >= props.totalPages - 1,
            onClick: goNext,
          },
          '下一頁'
        ),
      ])
  },
})

describe('Pagination', () => {
  beforeEach(() => {
    vi.clearAllMocks()
  })

  describe('page info display', () => {
    it('should display current page and total pages (1-indexed)', () => {
      const wrapper = mount(PaginationRef, {
        props: { currentPage: 0, totalPages: 5 },
      })
      expect(wrapper.find('.page-info').text()).toBe('1 / 5')
    })

    it('should display page 3 of 10', () => {
      const wrapper = mount(PaginationRef, {
        props: { currentPage: 2, totalPages: 10 },
      })
      expect(wrapper.find('.page-info').text()).toBe('3 / 10')
    })

    it('should display 1 / 1 for single page', () => {
      const wrapper = mount(PaginationRef, {
        props: { currentPage: 0, totalPages: 1 },
      })
      expect(wrapper.find('.page-info').text()).toBe('1 / 1')
    })
  })

  describe('prev button', () => {
    it('should be disabled on first page (page=0)', () => {
      const wrapper = mount(PaginationRef, {
        props: { currentPage: 0, totalPages: 5 },
      })
      expect(wrapper.find('.prev-btn').attributes('disabled')).toBeDefined()
    })

    it('should be enabled when not on first page', () => {
      const wrapper = mount(PaginationRef, {
        props: { currentPage: 2, totalPages: 5 },
      })
      expect(wrapper.find('.prev-btn').attributes('disabled')).toBeUndefined()
    })

    it('should emit page-change with previous page when clicked', async () => {
      const wrapper = mount(PaginationRef, {
        props: { currentPage: 3, totalPages: 5 },
      })
      await wrapper.find('.prev-btn').trigger('click')

      expect(wrapper.emitted('page-change')).toHaveLength(1)
      expect(wrapper.emitted('page-change')![0]).toEqual([2])
    })

    it('should not emit when disabled and clicked on first page', async () => {
      const wrapper = mount(PaginationRef, {
        props: { currentPage: 0, totalPages: 5 },
      })
      await wrapper.find('.prev-btn').trigger('click')

      expect(wrapper.emitted('page-change')).toBeUndefined()
    })
  })

  describe('next button', () => {
    it('should be disabled on last page', () => {
      const wrapper = mount(PaginationRef, {
        props: { currentPage: 4, totalPages: 5 },
      })
      expect(wrapper.find('.next-btn').attributes('disabled')).toBeDefined()
    })

    it('should be enabled when not on last page', () => {
      const wrapper = mount(PaginationRef, {
        props: { currentPage: 1, totalPages: 5 },
      })
      expect(wrapper.find('.next-btn').attributes('disabled')).toBeUndefined()
    })

    it('should emit page-change with next page when clicked', async () => {
      const wrapper = mount(PaginationRef, {
        props: { currentPage: 1, totalPages: 5 },
      })
      await wrapper.find('.next-btn').trigger('click')

      expect(wrapper.emitted('page-change')).toHaveLength(1)
      expect(wrapper.emitted('page-change')![0]).toEqual([2])
    })

    it('should not emit when disabled and clicked on last page', async () => {
      const wrapper = mount(PaginationRef, {
        props: { currentPage: 4, totalPages: 5 },
      })
      await wrapper.find('.next-btn').trigger('click')

      expect(wrapper.emitted('page-change')).toBeUndefined()
    })
  })

  describe('single page scenario', () => {
    it('should disable both prev and next on single page', () => {
      const wrapper = mount(PaginationRef, {
        props: { currentPage: 0, totalPages: 1 },
      })
      expect(wrapper.find('.prev-btn').attributes('disabled')).toBeDefined()
      expect(wrapper.find('.next-btn').attributes('disabled')).toBeDefined()
    })
  })

  describe('boundary: two pages', () => {
    it('should disable prev on first page, enable next', () => {
      const wrapper = mount(PaginationRef, {
        props: { currentPage: 0, totalPages: 2 },
      })
      expect(wrapper.find('.prev-btn').attributes('disabled')).toBeDefined()
      expect(wrapper.find('.next-btn').attributes('disabled')).toBeUndefined()
    })

    it('should enable prev on second page, disable next', () => {
      const wrapper = mount(PaginationRef, {
        props: { currentPage: 1, totalPages: 2 },
      })
      expect(wrapper.find('.prev-btn').attributes('disabled')).toBeUndefined()
      expect(wrapper.find('.next-btn').attributes('disabled')).toBeDefined()
    })
  })

  describe('zero pages edge case', () => {
    it('should disable both buttons when totalPages is 0', () => {
      const wrapper = mount(PaginationRef, {
        props: { currentPage: 0, totalPages: 0 },
      })
      expect(wrapper.find('.prev-btn').attributes('disabled')).toBeDefined()
      expect(wrapper.find('.next-btn').attributes('disabled')).toBeDefined()
    })
  })
})

import { defineStore } from 'pinia'
import { getTasks as apiGetTasks, createTask as apiCreateTask } from '@/api/tasks'

export const useTaskStore = defineStore('task', {
  state: () => ({
    tasks: [] as any[],
    page: 0,
    size: 20,
    totalElements: 0,
    totalPages: 0,
    keyword: '',
    priorityFilter: '',
    statusFilter: '',
    loading: false,
    error: null as string | null,
  }),

  actions: {
    async fetchTasks() {
      this.loading = true
      this.error = null
      try {
        const data = await apiGetTasks({
          page: this.page,
          size: this.size,
          keyword: this.keyword,
          priority: this.priorityFilter,
          status: this.statusFilter,
        })
        this.tasks = data.content
        this.page = data.page
        this.totalElements = data.totalElements
        this.totalPages = data.totalPages
      } catch (e: any) {
        this.error = e.message
      } finally {
        this.loading = false
      }
    },

    setKeyword(kw: string) {
      this.keyword = kw
      this.page = 0
    },

    setPriorityFilter(p: string) {
      this.priorityFilter = p
      this.page = 0
    },

    setStatusFilter(s: string) {
      this.statusFilter = s
      this.page = 0
    },

    setPage(p: number) {
      this.page = p
    },

    async createTask(data: Record<string, any>) {
      await apiCreateTask(data)
      await this.fetchTasks()
    },
  },
})

